  1→/**
  2→ * Google Drive Sync Service
  3→ *
  4→ * Enterprise-grade service for syncing extension data to Google Drive
  5→ * Uses Chrome Identity API for OAuth2 and Drive REST API v3 for storage
  6→ *
  7→ * Stores folders, prompts, and starred messages as separate files:
  8→ * - gemini-voyager-folders.json
  9→ * - gemini-voyager-prompts.json
 10→ * - gemini-voyager-starred.json
 11→ */
 12→import type { FolderData } from '@/core/types/folder';
 13→import type {
 14→  FolderExportPayload,
 15→  ForkExportPayload,
 16→  ForkNodesDataSync,
 17→  PromptExportPayload,
 18→  PromptItem,
 19→  StarredExportPayload,
 20→  StarredMessagesDataSync,
 21→  SyncAccountScope,
 22→  SyncMode,
 23→  SyncPlatform,
 24→  SyncState,
 25→} from '@/core/types/sync';
 26→import { DEFAULT_SYNC_STATE } from '@/core/types/sync';
 27→import { hashString } from '@/core/utils/hash';
 28→import { EXTENSION_VERSION } from '@/core/utils/version';
 29→
 30→const FOLDERS_FILE_NAME = 'gemini-voyager-folders.json';
 31→const AISTUDIO_FOLDERS_FILE_NAME = 'gemini-voyager-aistudio-folders.json';
 32→const PROMPTS_FILE_NAME = 'gemini-voyager-prompts.json';
 33→const STARRED_FILE_NAME = 'gemini-voyager-starred.json';
 34→const FORKS_FILE_NAME = 'gemini-voyager-forks.json';
 35→const BACKUP_FOLDER_NAME = 'Gemini Voyager Data';
 36→const DRIVE_API_BASE = 'https://www.googleapis.com/drive/v3';
 37→const DRIVE_UPLOAD_BASE = 'https://www.googleapis.com/upload/drive/v3';
 38→
 39→// Retry configuration
 40→const MAX_RETRIES = 3;
 41→const INITIAL_RETRY_DELAY_MS = 1000;
 42→const IDENTITY_TOKEN_TTL_SECONDS = 55 * 60;
 43→
 44→/**
 45→ * Google Drive Sync Service
 46→ * Handles authentication, upload, and download of sync data as separate files
 47→ */
 48→export class GoogleDriveSyncService {
 49→  private state: SyncState = { ...DEFAULT_SYNC_STATE };
 50→  private foldersFileId: string | null = null;
 51→  private aistudioFoldersFileId: string | null = null;
 52→  private promptsFileId: string | null = null;
 53→  private starredFileId: string | null = null;
 54→  private forksFileId: string | null = null;
 55→  private backupFolderId: string | null = null;
 56→  private fileIdByName: Record<string, string> = {};
 57→  private stateChangeCallback: ((state: SyncState) => void) | null = null;
 58→  private accessToken: string | null = null;
 59→  private tokenExpiry: number = 0;
 60→  private stateLoadPromise: Promise<void> | null = null;
 61→
 62→  constructor() {
 63→    this.stateLoadPromise = this.loadState();
 64→  }
 65→
 66→  onStateChange(callback: (state: SyncState) => void): void {
 67→    this.stateChangeCallback = callback;
 68→  }
 69→
 70→  /**
 71→   * Ensure state is loaded before returning
 72→   */
 73→  async getState(): Promise<SyncState> {
 74→    if (this.stateLoadPromise) {
 75→      await this.stateLoadPromise;
 76→    }
 77→    return { ...this.state };
 78→  }
 79→
 80→  async setMode(mode: SyncMode): Promise<void> {
 81→    this.state.mode = mode;
 82→    await this.saveState();
 83→    this.notifyStateChange();
 84→  }
 85→
 86→  async authenticate(interactive: boolean = true): Promise<boolean> {
 87→    try {
 88→      this.updateState({ isSyncing: true, error: null });
 89→      const token = await this.getAuthToken(interactive);
 90→      if (!token) {
 91→        // If not interactive and no token, just return false silently
 92→        if (!interactive) {
 93→          this.updateState({ isAuthenticated: false, isSyncing: false });
 94→          return false;
 95→        }
 96→        throw new Error('Failed to obtain auth token');
 97→      }
 98→      this.updateState({ isAuthenticated: true, isSyncing: false });
 99→      return true;
100→    } catch (error) {
101→      const errorMessage = error instanceof Error ? error.message : 'Authentication failed';
102→      console.error('[GoogleDriveSyncService] Authentication failed:', error);
103→      this.updateState({ isAuthenticated: false, isSyncing: false, error: errorMessage });
104→      return false;
105→    }
106→  }
107→
108→  async signOut(): Promise<void> {
109→    try {
110→      if (this.accessToken) {
111→        await this.removeCachedAuthToken(this.accessToken);
112→        await fetch(`https://accounts.google.com/o/oauth2/revoke?token=${this.accessToken}`);
113→      }
114→    } catch (error) {
115→      console.warn('[GoogleDriveSyncService] Sign out warning:', error);
116→    }
117→    await this.clearToken();
118→    this.foldersFileId = null;
119→    this.promptsFileId = null;
120→    this.starredFileId = null;
121→    this.forksFileId = null;
122→    this.backupFolderId = null;
123→    this.fileIdByName = {};
124→    this.updateState({ isAuthenticated: false, lastSyncTime: null, error: null });
125→    await this.saveState();
126→  }
127→
128→  /**
129→   * Upload folders, prompts, and starred messages as separate files to Google Drive
130→   * @param folders Folder data to upload
131→   * @param prompts Prompt items (only for Gemini platform)
132→   * @param starred Starred messages (only for Gemini platform)
133→   * @param interactive Whether to show auth prompt if needed
134→   * @param platform Platform to upload for ('gemini' | 'aistudio')
135→   */
136→  async upload(
137→    folders: FolderData,
138→    prompts: PromptItem[],
139→    starred: StarredMessagesDataSync | null = null,
140→    interactive: boolean = true,
141→    platform: SyncPlatform = 'gemini',
142→    forks: ForkNodesDataSync | null = null,
143→    accountScope: SyncAccountScope | null = null,
144→  ): Promise<boolean> {
145→    try {
146→      this.updateState({ isSyncing: true, error: null });
147→
148→      const token = await this.getAuthToken(interactive);
149→      if (!token) {
150→        if (!interactive) {
151→          console.log(
152→            '[GoogleDriveSyncService] Upload skipped: Not authenticated (non-interactive)',
153→          );
154→          this.updateState({ isSyncing: false, isAuthenticated: false });
155→          return false;
156→        }
157→        throw new Error('Not authenticated');
158→      }
159→
160→      const now = new Date();
161→
162→      // Create folder payload
163→      const folderPayload: FolderExportPayload = {
164→        format: 'gemini-voyager.folders.v1',
165→        exportedAt: now.toISOString(),
166→        version: EXTENSION_VERSION,
167→        data: folders,
168→      };
169→
170→      // Create prompt payload
171→      const promptPayload: PromptExportPayload = {
172→        format: 'gemini-voyager.prompts.v1',
173→        exportedAt: now.toISOString(),
174→        version: EXTENSION_VERSION,
175→        items: prompts,
176→      };
177→
178→      // Upload folders file (platform-specific)
179→      const foldersBaseFileName =
180→        platform === 'aistudio' ? AISTUDIO_FOLDERS_FILE_NAME : FOLDERS_FILE_NAME;
181→      const foldersFileName = this.getFileNameForScope(foldersBaseFileName, accountScope);
182→      const foldersType = platform === 'aistudio' ? 'aistudio-folders' : 'folders';
183→      const foldersFileIdToUse = await this.ensureFileId(token, foldersFileName, foldersType);
184→      await this.uploadFileWithRetry(token, foldersFileIdToUse, folderPayload);
185→      console.log(`[GoogleDriveSyncService] ${platform} folders uploaded successfully`);
186→
187→      // Upload prompts file (shared between Gemini and AI Studio)
188→      if (prompts.length > 0) {
189→        const promptsFileName = this.getFileNameForScope(PROMPTS_FILE_NAME, accountScope);
190→        const promptsFileId = await this.ensureFileId(token, promptsFileName, 'prompts');
191→        await this.uploadFileWithRetry(token, promptsFileId, promptPayload);
192→        console.log('[GoogleDriveSyncService] Prompts uploaded successfully');
193→      }
194→
195→      // Upload starred messages file (only for Gemini platform)
196→      if (platform === 'gemini' && starred) {
197→        // Truncate content in starred messages to save storage space
198→        const MAX_CONTENT_LENGTH = 60;
199→        const truncatedStarred: StarredMessagesDataSync = {
200→          messages: Object.fromEntries(
201→            Object.entries(starred.messages).map(([convId, messages]) => [
202→              convId,
203→              messages.map((msg) => ({
204→                ...msg,
205→                content:
206→                  msg.content.length > MAX_CONTENT_LENGTH
207→                    ? msg.content.slice(0, MAX_CONTENT_LENGTH) + '...'
208→                    : msg.content,
209→              })),
210→            ]),
211→          ),
212→        };
213→
214→        const starredPayload: StarredExportPayload = {
215→          format: 'gemini-voyager.starred.v1',
216→          exportedAt: now.toISOString(),
217→          version: EXTENSION_VERSION,
218→          data: truncatedStarred,
219→        };
220→        const starredFileName = this.getFileNameForScope(STARRED_FILE_NAME, accountScope);
221→        const starredFileId = await this.ensureFileId(token, starredFileName, 'starred');
222→        await this.uploadFileWithRetry(token, starredFileId, starredPayload);
223→        console.log('[GoogleDriveSyncService] Starred messages uploaded successfully');
224→      }
225→
226→      // Upload fork nodes file (only for Gemini platform)
227→      if (platform === 'gemini' && forks) {
228→        const forksPayload: ForkExportPayload = {
229→          format: 'gemini-voyager.forks.v1',
230→          exportedAt: now.toISOString(),
231→          version: EXTENSION_VERSION,
232→          data: forks,
233→        };
234→        const forksFileName = this.getFileNameForScope(FORKS_FILE_NAME, accountScope);
235→        const forksFileId = await this.ensureFileId(token, forksFileName, 'forks');
236→        await this.uploadFileWithRetry(token, forksFileId, forksPayload);
237→        console.log('[GoogleDriveSyncService] Fork nodes uploaded successfully');
238→      }
239→
240→      const uploadTime = Date.now();
241→      // Update platform-specific upload time
242→      if (platform === 'aistudio') {
243→        this.updateState({ isSyncing: false, lastUploadTimeAIStudio: uploadTime, error: null });
244→      } else {
245→        this.updateState({ isSyncing: false, lastUploadTime: uploadTime, error: null });
246→      }
247→      await this.saveState();
248→
249→      const fileCount = platform === 'gemini' ? (starred ? (forks ? 4 : 3) : 2) : 1;
250→      console.log(
251→        `[GoogleDriveSyncService] Upload successful - ${fileCount} file(s) for ${platform}`,
252→      );
253→      return true;
254→    } catch (error) {
255→      const errorMessage = error instanceof Error ? error.message : 'Upload failed';
256→      console.error('[GoogleDriveSyncService] Upload failed:', error);
257→      this.updateState({ isSyncing: false, error: errorMessage });
258→      return false;
259→    }
260→  }
261→
262→  /**
263→   * Download folders, prompts, and starred messages from separate files in Google Drive
264→   * Returns { folders, prompts, starred } or null if no files exist
265→   * @param interactive Whether to show auth prompt if needed
266→   * @param platform Platform to download for ('gemini' | 'aistudio')
267→   */
268→  async download(
269→    interactive: boolean = true,
270→    platform: SyncPlatform = 'gemini',
271→    accountScope: SyncAccountScope | null = null,
272→  ): Promise<{
273→    folders: FolderExportPayload | null;
274→    prompts: PromptExportPayload | null;
275→    starred: StarredExportPayload | null;
276→    forks: ForkExportPayload | null;
277→  } | null> {
278→    try {
279→      this.updateState({ isSyncing: true, error: null });
280→
281→      const token = await this.getAuthToken(interactive);
282→      if (!token) {
283→        if (!interactive) {
284→          console.log(
285→            '[GoogleDriveSyncService] Download skipped: Not authenticated (non-interactive)',
286→          );
287→          this.updateState({ isSyncing: false, isAuthenticated: false });
288→          return null;
289→        }
290→        throw new Error('Not authenticated');
291→      }
292→
293→      // Download folders file (platform-specific)
294→      const foldersBaseFileName =
295→        platform === 'aistudio' ? AISTUDIO_FOLDERS_FILE_NAME : FOLDERS_FILE_NAME;
296→      const foldersFileId = await this.findFileForScope(token, foldersBaseFileName, accountScope);
297→      let folders: FolderExportPayload | null = null;
298→      if (foldersFileId) {
299→        folders = await this.downloadFileWithRetry(token, foldersFileId);
300→        console.log(`[GoogleDriveSyncService] ${platform} folders downloaded`);
301→      }
302→
303→      // Download prompts file (shared between Gemini and AI Studio)
304→      let prompts: PromptExportPayload | null = null;
305→      const promptsFileId = await this.findFileForScope(token, PROMPTS_FILE_NAME, accountScope);
306→      if (promptsFileId) {
307→        prompts = await this.downloadFileWithRetry(token, promptsFileId);
308→        console.log('[GoogleDriveSyncService] Prompts downloaded');
309→      }
310→
311→      // Download starred messages file (only for Gemini platform)
312→      let starred: StarredExportPayload | null = null;
313→      if (platform === 'gemini') {
314→        const starredFileId = await this.findFileForScope(token, STARRED_FILE_NAME, accountScope);
315→        if (starredFileId) {
316→          starred = await this.downloadFileWithRetry(token, starredFileId);
317→          console.log('[GoogleDriveSyncService] Starred messages downloaded');
318→        }
319→      }
320→
321→      // Download fork nodes file (only for Gemini platform)
322→      let forks: ForkExportPayload | null = null;
323→      if (platform === 'gemini') {
324→        const forksFileId = await this.findFileForScope(token, FORKS_FILE_NAME, accountScope);
325→        if (forksFileId) {
326→          forks = await this.downloadFileWithRetry(token, forksFileId);
327→          console.log('[GoogleDriveSyncService] Fork nodes downloaded');
328→        }
329→      }
330→
331→      if (!folders && !prompts && !starred && !forks) {
332→        console.log(`[GoogleDriveSyncService] No sync files found for ${platform}`);
333→        this.updateState({ isSyncing: false });
334→        return null;
335→      }
336→
337→      const syncTime = Date.now();
338→      // Update platform-specific sync time
339→      if (platform === 'aistudio') {
340→        this.updateState({ isSyncing: false, lastSyncTimeAIStudio: syncTime, error: null });
341→      } else {
342→        this.updateState({ isSyncing: false, lastSyncTime: syncTime, error: null });
343→      }
344→      await this.saveState();
345→
346→      return { folders, prompts, starred, forks };
347→    } catch (error) {
348→      const errorMessage = error instanceof Error ? error.message : 'Download failed';
349→      console.error('[GoogleDriveSyncService] Download failed:', error);
350→      this.updateState({ isSyncing: false, error: errorMessage });
351→      return null;
352→    }
353→  }
354→
355→  // ============== Private Methods ==============
356→
357→  private async loadCachedToken(): Promise<void> {
358→    try {
359→      const result = await chrome.storage.local.get(['gvAccessToken', 'gvTokenExpiry']);
360→      if (result.gvAccessToken && result.gvTokenExpiry && result.gvTokenExpiry > Date.now()) {
361→        this.accessToken = result.gvAccessToken;
362→        this.tokenExpiry = result.gvTokenExpiry;
363→        console.log('[GoogleDriveSyncService] Loaded cached token');
364→      }
365→    } catch (error) {
366→      console.error('[GoogleDriveSyncService] Failed to load cached token:', error);
367→    }
368→  }
369→
370→  private async saveToken(token: string, expiresIn: number): Promise<void> {
371→    this.accessToken = token;
372→    this.tokenExpiry = Date.now() + expiresIn * 1000 - 60000;
373→    try {
374→      await chrome.storage.local.set({ gvAccessToken: token, gvTokenExpiry: this.tokenExpiry });
375→    } catch (error) {
376→      console.error('[GoogleDriveSyncService] Failed to save token:', error);
377→    }
378→  }
379→
380→  private async clearToken(): Promise<void> {
381→    this.accessToken = null;
382→    this.tokenExpiry = 0;
383→    try {
384→      await chrome.storage.local.remove(['gvAccessToken', 'gvTokenExpiry']);
385→    } catch (error) {
386→      console.error('[GoogleDriveSyncService] Failed to clear token:', error);
387→    }
388→  }
389→
390→  private isUserDeniedAuthError(message: string): boolean {
391→    const normalized = message.toLowerCase();
392→    return (
393→      normalized.includes('did not approve access') ||
394→      normalized.includes('user denied') ||
395→      normalized.includes('access_denied')
396→    );
397→  }
398→
399→  private extractIdentityToken(result: unknown): string | null {
400→    if (typeof result === 'string' && result.trim()) {
401→      return result;
402→    }
403→
404→    if (typeof result === 'object' && result !== null) {
405→      const token = (result as { token?: unknown }).token;
406→      if (typeof token === 'string' && token.trim()) {
407→        return token;
408→      }
409→    }
410→
411→    return null;
412→  }
413→
414→  private async requestIdentityAuthToken(
415→    interactive: boolean,
416→  ): Promise<{ token: string | null; userDenied: boolean }> {
417→    const identity = chrome.identity;
418→    if (!identity?.getAuthToken) {
419→      return { token: null, userDenied: false };
420→    }
421→
422→    try {
423→      const tokenResult = await new Promise<unknown>((resolve, reject) => {
424→        identity.getAuthToken({ interactive }, (token) => {
425→          if (chrome.runtime.lastError) {
426→            reject(new Error(chrome.runtime.lastError.message));
427→          } else {
428→            resolve(token);
429→          }
430→        });
431→      });
432→
433→      const token = this.extractIdentityToken(tokenResult);
434→      if (!token) {
435→        return { token: null, userDenied: false };
436→      }
437→
438→      // getAuthToken does not provide expiry; keep a short TTL and persist for worker restarts.
439→      await this.saveToken(token, IDENTITY_TOKEN_TTL_SECONDS);
440→      return { token, userDenied: false };
441→    } catch (error) {
442→      const message = error instanceof Error ? error.message : String(error);
443→      const userDenied = this.isUserDeniedAuthError(message);
444→      if (!userDenied) {
445→        console.warn('[GoogleDriveSyncService] identity.getAuthToken failed:', error);
446→      }
447→      return { token: null, userDenied };
448→    }
449→  }
450→
451→  private async getTokenFromIdentity(
452→    interactive: boolean,
453→  ): Promise<{ token: string | null; userDenied: boolean }> {
454→    if (!chrome.identity?.getAuthToken) {
455→      return { token: null, userDenied: false };
456→    }
457→
458→    const nonInteractiveResult = await this.requestIdentityAuthToken(false);
459→    if (nonInteractiveResult.token) {
460→      return nonInteractiveResult;
461→    }
462→
463→    if (!interactive) {
464→      return { token: null, userDenied: false };
465→    }
466→
467→    return this.requestIdentityAuthToken(true);
468→  }
469→
470→  private async removeCachedAuthToken(token: string): Promise<void> {
471→    const identity = chrome.identity;
472→    if (!identity?.removeCachedAuthToken) {
473→      return;
474→    }
475→
476→    await new Promise<void>((resolve) => {
477→      identity.removeCachedAuthToken({ token }, () => resolve());
478→    });
479→  }
480→
481→  private async getTokenFromLegacyWebAuthFlow(): Promise<string | null> {
482→    const manifest = chrome.runtime.getManifest();
483→    const clientId = manifest.oauth2?.client_id;
484→    const scopes = manifest.oauth2?.scopes?.join(' ');
485→
486→    if (!clientId || !scopes) {
487→      console.error('[GoogleDriveSyncService] Missing oauth2 config');
488→      return null;
489→    }
490→
491→    const redirectUrl = chrome.identity.getRedirectURL();
492→    console.log('[GoogleDriveSyncService] Auth flow starting with redirectUrl:', redirectUrl);
493→    const authUrl = new URL('https://accounts.google.com/o/oauth2/v2/auth');
494→    authUrl.searchParams.set('client_id', clientId);
495→    authUrl.searchParams.set('redirect_uri', redirectUrl);
496→    authUrl.searchParams.set('response_type', 'token');
497→    authUrl.searchParams.set('scope', scopes);
498→
499→    try {
500→      const responseUrl = await new Promise<string>((resolve, reject) => {
501→        chrome.identity.launchWebAuthFlow(
502→          { url: authUrl.toString(), interactive: true },
503→          (response) => {
504→            if (chrome.runtime.lastError) {
505→              reject(new Error(chrome.runtime.lastError.message));
506→            } else if (response) {
507→              resolve(response);
508→            } else {
509→              reject(new Error('No response from auth flow'));
510→            }
511→          },
512→        );
513→      });
514→
515→      const url = new URL(responseUrl);
516→      const hashParams = new URLSearchParams(url.hash.substring(1));
517→      const accessToken = hashParams.get('access_token');
518→      const expiresIn = parseInt(hashParams.get('expires_in') || '3600', 10);
519→
520→      if (accessToken) {
521→        await this.saveToken(accessToken, expiresIn);
522→        return accessToken;
523→      }
524→      return null;
525→    } catch (error) {
526→      console.error('[GoogleDriveSyncService] Auth flow failed:', error);
527→      return null;
528→    }
529→  }
530→
531→  private async getAuthToken(interactive: boolean): Promise<string | null> {
532→    if (this.accessToken && this.tokenExpiry > Date.now()) {
533→      return this.accessToken;
534→    }
535→
536→    if (this.accessToken && this.tokenExpiry <= Date.now()) {
537→      this.accessToken = null;
538→      this.tokenExpiry = 0;
539→    }
540→
541→    await this.loadCachedToken();
542→    if (this.accessToken && this.tokenExpiry > Date.now()) {
543→      return this.accessToken;
544→    }
545→
546→    const supportsIdentityApi = !!chrome.identity?.getAuthToken;
547→    if (supportsIdentityApi) {
548→      const identityResult = await this.getTokenFromIdentity(interactive);
549→      if (identityResult.token) {
550→        return identityResult.token;
551→      }
552→
553→      if (!interactive) {
554→        return null;
555→      }
556→
557→      // Fallback: always try launchWebAuthFlow when getAuthToken fails.
558→      // Some browsers (Arc) or Chrome versions may show an OAuth error page
559→      // during getAuthToken, which looks like "user denied" when dismissed,
560→      // but launchWebAuthFlow with a registered redirect URI can still succeed.
561→      return this.getTokenFromLegacyWebAuthFlow();
562→    }
563→
564→    if (!interactive) {
565→      return null;
566→    }
567→
568→    return this.getTokenFromLegacyWebAuthFlow();
569→  }
570→
571→  private async findFile(token: string, fileName: string): Promise<string | null> {
572→    const query = encodeURIComponent(`name='${fileName}' and trashed=false`);
573→    const url = `${DRIVE_API_BASE}/files?q=${query}&fields=files(id,name)`;
574→    const response = await fetch(url, { headers: { Authorization: `Bearer ${token}` } });
575→    if (!response.ok) {
576→      throw new Error(`Failed to search files: ${response.status}`);
577→    }
578→    const result = await response.json();
579→    return result.files?.[0]?.id || null;
580→  }
581→
582→  private getFileNameForScope(baseFileName: string, accountScope: SyncAccountScope | null): string {
583→    if (!accountScope) return baseFileName;
584→
585→    const suffix = `acct-${hashString(accountScope.accountKey)}`;
586→    const dotIndex = baseFileName.lastIndexOf('.');
587→    if (dotIndex <= 0) {
588→      return `${baseFileName}.${suffix}`;
589→    }
590→    return `${baseFileName.slice(0, dotIndex)}.${suffix}${baseFileName.slice(dotIndex)}`;
591→  }
592→
593→  private async findFileForScope(
594→    token: string,
595→    baseFileName: string,
596→    accountScope: SyncAccountScope | null,
597→  ): Promise<string | null> {
598→    if (!accountScope) {
599→      return this.findFile(token, baseFileName);
600→    }
601→
602→    const scopedFileName = this.getFileNameForScope(baseFileName, accountScope);
603→    const scopedFileId = await this.findFile(token, scopedFileName);
604→    if (scopedFileId) return scopedFileId;
605→
606→    // Backward compatibility: allow reading legacy shared file before user uploads scoped data.
607→    return this.findFile(token, baseFileName);
608→  }
