610→  private async ensureFileId(
611→    token: string,
612→    fileName: string,
613→    type: 'folders' | 'aistudio-folders' | 'prompts' | 'starred' | 'forks',
614→  ): Promise<string> {
615→    // 1. Ensure backup folder exists
616→    const folderId = await this.ensureBackupFolder(token);
617→
618→    // 2. Check if we have a valid cached file ID
619→    const currentId = this.fileIdByName[fileName] ?? null;
620→
621→    if (currentId) {
622→      const parents = await this.getFileParents(token, currentId);
623→      if (parents) {
624→        // File exists
625→        if (!parents.includes(folderId)) {
626→          // File exists but not in the backup folder, move it
627→          console.log(`[GoogleDriveSyncService] Moving ${fileName} to backup folder`);
628→          await this.moveFile(token, currentId, folderId, parents);
629→        }
630→        return currentId;
631→      }
632→      // If checkFileParents returns null, the file doesn't exist (e.g. deleted externally), proceed to find/create
633→    }
634→
635→    // 3. Search for the file globally (in case it was created before but we lost the ID reference)
636→    const existingId = await this.findFile(token, fileName);
637→    if (existingId) {
638→      // Found existing file
639→      this.setFileIdForType(type, existingId);
640→      this.fileIdByName[fileName] = existingId;
641→
642→      // Check if it needs moving
643→      const parents = await this.getFileParents(token, existingId);
644→      if (parents && !parents.includes(folderId)) {
645→        console.log(`[GoogleDriveSyncService] Moving existing ${fileName} to backup folder`);
646→        await this.moveFile(token, existingId, folderId, parents);
647→      }
648→      return existingId;
649→    }
650→
651→    // 4. Create new file in the backup folder
652→    console.log(`[GoogleDriveSyncService] Creating new file ${fileName} in backup folder`);
653→    const newId = await this.createFile(token, fileName, folderId);
654→    this.setFileIdForType(type, newId);
655→    this.fileIdByName[fileName] = newId;
656→    return newId;
657→  }
