682→  private async ensureBackupFolder(token: string): Promise<string> {
683→    if (this.backupFolderId) {
684→      // Verify it still exists
685→      const exists = await this.checkFileExists(token, this.backupFolderId);
686→      if (exists) return this.backupFolderId;
687→    }
688→
689→    // Search for folder
690→    const query = encodeURIComponent(
691→      `name='${BACKUP_FOLDER_NAME}' and mimeType='application/vnd.google-apps.folder' and trashed=false`,
692→    );
693→    const url = `${DRIVE_API_BASE}/files?q=${query}&fields=files(id)`;
694→    const response = await fetch(url, { headers: { Authorization: `Bearer ${token}` } });
695→    if (!response.ok) throw new Error('Failed to search for backup folder');
696→
697→    const data = await response.json();
698→    const existingId = data.files?.[0]?.id;
699→
700→    if (existingId) {
701→      this.backupFolderId = existingId;
702→      return existingId;
703→    }
704→
705→    // Create folder
706→    const metadata = {
707→      name: BACKUP_FOLDER_NAME,
708→      mimeType: 'application/vnd.google-apps.folder',
709→    };
710→    const createResponse = await fetch(`${DRIVE_API_BASE}/files`, {
711→      method: 'POST',
712→      headers: {
713→        Authorization: `Bearer ${token}`,
714→        'Content-Type': 'application/json',
715→      },
716→      body: JSON.stringify(metadata),
717→    });
718→
719→    if (!createResponse.ok) throw new Error('Failed to create backup folder');
720→    const folderData = await createResponse.json();
721→    this.backupFolderId = folderData.id;
722→    console.log('[GoogleDriveSyncService] Created backup folder:', this.backupFolderId);
723→    return folderData.id;
724→  }
