726→  private async getFileParents(token: string, fileId: string): Promise<string[] | null> {
727→    try {
728→      // Also check if file is trashed - if so, treat as non-existent
729→      const response = await fetch(`${DRIVE_API_BASE}/files/${fileId}?fields=parents,trashed`, {
730→        headers: { Authorization: `Bearer ${token}` },
731→      });
732→      if (response.status === 404) return null;
733→      if (!response.ok) return null;
734→      const data = await response.json();
735→      // If file is in trash, treat as non-existent so we create a new one
736→      if (data.trashed) {
737→        console.log(`[GoogleDriveSyncService] File ${fileId} is in trash, will create new one`);
738→        return null;
739→      }
740→      return data.parents || [];
741→    } catch {
742→      return null;
743→    }
744→  }
