746→  private async moveFile(
747→    token: string,
748→    fileId: string,
749→    targetFolderId: string,
750→    currentParents: string[],
751→  ): Promise<void> {
752→    const previousParents = currentParents.join(',');
753→    const url = `${DRIVE_API_BASE}/files/${fileId}?addParents=${targetFolderId}&removeParents=${previousParents}&fields=id,parents`;
754→    const response = await fetch(url, {
755→      method: 'PATCH',
756→      headers: { Authorization: `Bearer ${token}` },
757→    });
758→    if (!response.ok) {
759→      console.error('[GoogleDriveSyncService] Failed to move file:', await response.text());
760→      // Don't throw, just log. It's not critical if move fails, as long as we can access the file.
761→    }
762→  }
