775→  private async createFile(token: string, fileName: string, parentId?: string): Promise<string> {
776→    const metadata: { name: string; mimeType: string; parents?: string[] } = {
777→      name: fileName,
778→      mimeType: 'application/json',
779→    };
780→    if (parentId) {
781→      metadata.parents = [parentId];
782→    }
783→
784→    const response = await fetch(`${DRIVE_API_BASE}/files`, {
785→      method: 'POST',
786→      headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
787→      body: JSON.stringify(metadata),
788→    });
789→    if (!response.ok) {
790→      throw new Error(`Failed to create file: ${response.status}`);
791→    }
792→    const result = await response.json();
793→    return result.id;
794→  }
