796→  private async uploadFileWithRetry(token: string, fileId: string, data: unknown): Promise<void> {
797→    let delay = INITIAL_RETRY_DELAY_MS;
798→    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
799→      try {
800→        const url = `${DRIVE_UPLOAD_BASE}/files/${fileId}?uploadType=media`;
801→        const response = await fetch(url, {
802→          method: 'PATCH',
803→          headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
804→          body: JSON.stringify(data),
805→        });
806→        if (!response.ok) {
807→          throw new Error(`Upload failed: ${response.status}`);
808→        }
809→        return;
810→      } catch (error) {
811→        if (attempt === MAX_RETRIES) throw error;
812→        await this.sleep(delay);
813→        delay *= 2;
814→      }
815→    }
816→  }
817→
818→  private async downloadFileWithRetry<T>(token: string, fileId: string): Promise<T | null> {
819→    let delay = INITIAL_RETRY_DELAY_MS;
820→    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
821→      try {
822→        const url = `${DRIVE_API_BASE}/files/${fileId}?alt=media`;
823→        const response = await fetch(url, { headers: { Authorization: `Bearer ${token}` } });
824→        if (!response.ok) {
825→          if (response.status === 404) return null;
826→          throw new Error(`Download failed: ${response.status}`);
827→        }
828→        return await response.json();
829→      } catch (error) {
830→        if (attempt === MAX_RETRIES) throw error;
831→        await this.sleep(delay);
832→        delay *= 2;
833→      }
834→    }
835→    return null;
836→  }
