 61→  const resolveAccountSyncContext = useCallback(async (): Promise<{
 62→    accountScope: SyncAccountScope | null;
 63→    folderStorageKey: string;
 64→  }> => {
 65→    const baseFolderStorageKey = getBaseFolderStorageKey(platform);
 66→
 67→    const isolationEnabled = await accountIsolationService.isIsolationEnabled({ platform });
 68→    if (!isolationEnabled) {
 69→      return { accountScope: null, folderStorageKey: baseFolderStorageKey };
 70→    }
 71→
 72→    let pageUrl = '';
 73→    let routeUserId: string | null = null;
 74→    let email: string | null = null;
