 78→      pageUrl = tab?.url || '';
 79→      routeUserId = platform === 'gemini' ? extractRouteUserIdFromUrl(pageUrl) : null;
 80→
 81→      if (tab?.id) {
 82→        try {
 83→          const response = (await Promise.race([
 84→            chrome.tabs.sendMessage(tab.id, { type: 'gv.account.getContext' }),
 85→            new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), 400)),
 86→          ])) as { ok?: boolean; context?: { routeUserId?: string | null; email?: string | null } };
 87→
 88→          if (response?.ok && response.context) {
 89→            routeUserId = response.context.routeUserId ?? routeUserId;
 90→            email = response.context.email ?? null;
 91→          }
 92→        } catch {
 93→          // Ignore content-script lookup failure; we'll resolve with URL fallback.
 94→        }
 95→      }
 96→    } catch {
 97→      // Ignore tab query failure; account service will fallback to default scope.
 98→    }
 99→
100→    const resolvedScope = await accountIsolationService.resolveAccountScope({
101→      pageUrl,
102→      routeUserId,
103→      email,
104→    });
105→
106→    const accountScope: SyncAccountScope = {
107→      accountKey: resolvedScope.accountKey,
108→      accountId: resolvedScope.accountId,
109→      routeUserId: resolvedScope.routeUserId,
