148→
149→      let timeStr: string;
150→      if (diffMins < 1) {
151→        timeStr = t('justNow');
152→      } else if (diffMins < 60) {
153→        timeStr = `${diffMins} ${t('minutesAgo')}`;
154→      } else if (diffHours < 24) {
155→        timeStr = `${diffHours} ${t('hoursAgo')}`;
156→      } else if (diffDays === 1) {
157→        timeStr = t('yesterday');
