128→async function registerFetchInterceptor(): Promise<void> {
129→  if (!chrome.scripting?.registerContentScripts) return;
130→
131→  // Check if watermark remover feature is enabled
132→  const result = await chrome.storage.sync.get({ geminiWatermarkRemoverEnabled: true });
133→  const isEnabled = result.geminiWatermarkRemoverEnabled !== false;
134→
135→  try {
136→    // Always unregister first to update settings
137→    await chrome.scripting.unregisterContentScripts({ ids: [FETCH_INTERCEPTOR_SCRIPT_ID] });
138→  } catch {
139→    // No-op if script was not registered
140→  }
141→
142→  // Only register if watermark remover is enabled
143→  if (!isEnabled) {
144→    console.log('[Background] Fetch interceptor not registered (watermark remover disabled)');
145→    return;
146→  }
147→
148→  try {
149→    await chrome.scripting.registerContentScripts([
150→      {
151→        id: FETCH_INTERCEPTOR_SCRIPT_ID,
152→        js: ['fetchInterceptor.js'],
153→        matches: GEMINI_MATCHES,
154→        world: 'MAIN',
155→        runAt: 'document_start',
156→        persistAcrossSessions: true,
157→      },
158→    ]);
159→    console.log('[Background] Fetch interceptor registered for MAIN world');
160→  } catch (error) {
161→    console.error('[Background] Failed to register fetch interceptor:', error);
162→  }
163→}
