 5→/**
 6→ * Debounce function
 7→ */
 8→export function debounce<T extends (...args: Parameters<T>) => void>(
 9→  func: T,
10→  delay: number,
11→): (...args: Parameters<T>) => void {
12→  let timeoutId: number | null = null;
13→
14→  return (...args: Parameters<T>) => {
15→    if (timeoutId !== null) {
16→      clearTimeout(timeoutId);
17→    }
18→
19→    timeoutId = window.setTimeout(() => {
20→      func(...args);
21→      timeoutId = null;
22→    }, delay);
23→  };
24→}
25→
26→/**
27→ * Throttle function
28→ */
29→export function throttle<T extends (...args: Parameters<T>) => void>(
30→  func: T,
31→  delay: number,
32→): (...args: Parameters<T>) => void {
33→  let lastCall = 0;
34→
35→  return (...args: Parameters<T>) => {
36→    const now = Date.now();
37→
38→    if (now - lastCall >= delay) {
39→      lastCall = now;
40→      func(...args);
41→    }
42→  };
43→}
