45→/**
46→ * Retry with exponential backoff
47→ */
48→export async function retry<T>(
49→  fn: () => Promise<T>,
50→  options: {
51→    maxAttempts?: number;
52→    initialDelay?: number;
53→    maxDelay?: number;
54→    backoffFactor?: number;
55→  } = {},
56→): Promise<T> {
57→  const { maxAttempts = 3, initialDelay = 100, maxDelay = 5000, backoffFactor = 2 } = options;
58→
59→  let lastError: Error | undefined;
60→  let delay = initialDelay;
61→
62→  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
63→    try {
64→      return await fn();
65→    } catch (error) {
66→      lastError = error instanceof Error ? error : new Error(String(error));
67→
68→      if (attempt < maxAttempts) {
69→        await sleep(Math.min(delay, maxDelay));
70→        delay *= backoffFactor;
71→      }
72→    }
73→  }
74→
75→  throw lastError;
76→}
77→
78→/**
79→ * Sleep for specified milliseconds
80→ */
81→export function sleep(ms: number): Promise<void> {
82→  return new Promise((resolve) => setTimeout(resolve, ms));
83→}
84→
85→/**
86→ * Timeout wrapper for promises
87→ */
88→export async function withTimeout<T>(
89→  promise: Promise<T>,
90→  timeoutMs: number,
91→  timeoutError = new Error('Operation timed out'),
92→): Promise<T> {
93→  return Promise.race([
94→    promise,
95→    new Promise<T>((_, reject) => setTimeout(() => reject(timeoutError), timeoutMs)),
96→  ]);
97→}
